WITH src AS (SELECT r.pid, r.usesysid, r.usename, r.application_name, r.client_addr, r.client_hostname, r.client_port, r.backend_start, r.backend_xmin, r.state, r.sent_lsn, r.write_lsn, r.flush_lsn, r.replay_lsn, r.write_lag, r.flush_lag, r.replay_lag, r.sync_priority, r.sync_state, NULL AS reply_time FROM pg_stat_replication AS r) SELECT CHR(34) || :PKEY || CHR(34) AS pkey, CHR(34) || :DMA_SOURCE_ID || CHR(34) AS dma_source_id, CHR(34) || :DMA_MANUAL_ID || CHR(34) AS dma_manual_id, src.pid, src.usesysid, src.usename, src.application_name, src.client_addr, src.client_hostname, src.client_port, src.backend_start, src.backend_xmin, src.state, src.sent_lsn, src.write_lsn, src.flush_lsn, src.replay_lsn, src.write_lag, src.flush_lag, src.replay_lag, src.sync_priority, src.sync_state, src.reply_time FROM src